#include<bits/stdc++.h>#define int long long #define endl '\n'#define qwq ios::sync_with_stdio(false),cin.tie(0),cout.tie(0)using namespace std;int t,vis[55],a[55],n,sum;void dfs(int st){    if(st>n){        sum++;        if(sum<=n){            for(int i=1;i<=n;i++){                 cout<<a[i]<<" ";            }            cout<<endl;        }        return ;    }    for(int i=1;i<=n;i++){        if(vis[i] || a[st-1]+a[st-2]==i){            continue;        }        vis[i]=1;        a[st]=i;        dfs(st+1);        a[st]=0;        vis[i]=0;        if(sum>n){            return ;        }    }}signed main(){	qwq;	cin>>t;	while(t--){	    sum=0;	    cin>>n;	    dfs(1);	}	return 0;}